'use strict';

const optionsContainer = document.getElementById('options-container');
const articleElement = document.querySelector('.narrative-text');

async function sendToSillyTavern(text) {
    try {
        // Thử truy cập từ cửa sổ chaSillyTavernđối tượng tài liệu của
        const parentDoc = window.parent.document;
        if (!parentDoc) {
            throw new Error("Không thể truy cập đối tượng tài liệu của cửa sổ cha.");
        }

        // Đã tìm thấySillyTavernhộp nhập liệu chính của
        const inputArea = parentDoc.getElementById('send_textarea');
        if (!inputArea) {
            console.error("Không tìm thấySillyTavernhộp nhập liệu của ('#send_textarea')。");
            alert("Lỗi: Không thể tìm thấy trên trangSillyTavernhộp nhập liệu của.");
            return;
        }

        // Lấy văn bản hiện tại và nối thêm văn bản mới
        const currentText = inputArea.value;
        const newText = currentText.trim() ? `${currentText}\n${text}` : text;

        // Thiết lập giá trị văn bản mới
        inputArea.value = newText;

        // Kích hoạt mộtinputsự kiện, để thông báoSillyTavernnội dung nhập liệu đã thay đổi
        inputArea.dispatchEvent(new Event('input', { bubbles: true, cancelable: true }));

        // （Tùy chọn) Đặt tiêu điểm vào hộp nhập liệu
        inputArea.focus();

    } catch (error) {
        console.error('vớiSillyTavernĐã xảy ra lỗi khi tương tác:', error);
        // NếuDOMthao tác thất bại (ví dụ: do chính sách bảo mật chéo tên miền), thì dự phòng bằng khay nhớ tạm
        try {
            await navigator.clipboard.writeText(text);
            alert('Không thể sửa đổi trực tiếp hộp nhập liệu. Đã sao chép tùy chọn vào khay nhớ tạm.');
        } catch (clipError) {
            console.error('Thao tác khay nhớ tạm cũng thất bại:', clipError);
            alert('vớiSillyTavernTương tác thất bại và không thể truy cập khay nhớ tạm.');
        }
    }
}

function parseAndCreateOptions() {
    if (!articleElement || !optionsContainer) return;

    const optionElements = articleElement.querySelectorAll('option');
    const allOptions = [];

    optionElements.forEach(el => {
        allOptions.push(el.textContent.trim());
    });

    optionsContainer.innerHTML = '';
    if (allOptions.length > 0) {
        optionsContainer.style.display = 'flex';
        allOptions.forEach((optionText, index) => {
            const button = document.createElement('button');
            button.className = 'option-button';
            button.textContent = optionText;
            button.addEventListener('click', () => sendToSillyTavern(optionText));
            button.style.animationDelay = `${index * 0.07}s`;
            optionsContainer.appendChild(button);
        });
    } else {
        optionsContainer.style.display = 'none';
    }

    optionElements.forEach(el => {
        if (el.parentNode) {
            el.parentNode.removeChild(el);
        }
    });
}

document.addEventListener('DOMContentLoaded', () => {
    parseAndCreateOptions();

